                  import sailpoint.object.Filter;        

                  Filter filterManager = Filter.eq("isContractorManager","true");
                  Filter inactiveFilter = Filter.eq("inactive",false);
                  
                  Filter finalFilter = Filter.and(inactiveFilter,filterManager);

                  field.setFilterString(finalFilter.toString());

 
                  import sailpoint.object.Form; 
                  import sailpoint.object.Field; 
                  
                  if(form.getField("newManager") != null && form.getField("newManager").getValue() != null && form.getField("newManager").getValue().equals("Assign to Contractor Manager")){
                    return false;
                  }

                  return true;
